9	type Palette map[Ansi]Ansi
10	
11	const (
12		paletteKeyPrefix         = "p:"
13		paletteKeyError          = "palette: requested color %s does not exist in palette of colors %s"
14		paletteMaxRecursionDepth = 3 // allows 3 or less recursive resolutions
15		paletteRecursiveKeyError = "palette: recursive resolution of color %s returned palette reference %s and reached recursion depth %d"
16	)
17	
18	// ResolveColor gets a color value from the palette using given colorName.
19	// If colorName is not a palette reference, it is returned as is.
20	func (p Palette) ResolveColor(colorName Ansi) (Ansi, error) {
21		return p.resolveColor(colorName, 1, &colorName)
22	}
23	
24	// originalColorName is a pointer to save allocations
25	func (p Palette) resolveColor(colorName Ansi, depth int, originalColorName *Ansi) (Ansi, error) {
26		key, ok := asPaletteKey(colorName)
27		// colorName is not a palette key, return it as is
28		if !ok {
29			return colorName, nil
30		}
31	
32		color, ok := p[key]
33		if !ok {
34			return "", &PaletteKeyError{Key: key, palette: p}
35		}
36	
37		if _, isKey := isPaletteKey(color); isKey {
38			if depth > paletteMaxRecursionDepth {
39				return "", &PaletteRecursiveKeyError{Key: *originalColorName, Value: color, depth: depth}
40			}
41	
42			return p.resolveColor(color, depth+1, originalColorName)
43		}
44	
45		return color, nil
46	}
47	
48	func asPaletteKey(colorName Ansi) (Ansi, bool) {
49		prefix, isKey := isPaletteKey(colorName)
50		if !isKey {
51			return "", false
52		}
53	
54		key := strings.TrimPrefix(colorName.String(), prefix.String())
55	
56		return Ansi(key), true
57	}
58	
59	func isPaletteKey(colorName Ansi) (Ansi, bool) {
60		return paletteKeyPrefix, strings.HasPrefix(colorName.String(), paletteKeyPrefix)
61	}
62	
63	// PaletteKeyError records the missing Palette key.
64	type PaletteKeyError struct {
65		palette Palette
66		Key     Ansi
67	}
68	
69	func (p *PaletteKeyError) Error() string {
70		keys := make([]string, 0, len(p.palette))
71		for key := range p.palette {
72			keys = append(keys, key.String())
73		}
74		sort.Strings(keys)
75		allColors := strings.Join(keys, ",")
76		errorStr := fmt.Sprintf(paletteKeyError, p.Key, allColors)
77		return errorStr
78	}
79	
80	// PaletteRecursiveKeyError records the Palette key and resolved color value (which
81	// is also a Palette key)
82	type PaletteRecursiveKeyError struct {
83		Key   Ansi
84		Value Ansi
85		depth int
86	}
87	
88	func (p *PaletteRecursiveKeyError) Error() string {
89		errorStr := fmt.Sprintf(paletteRecursiveKeyError, p.Key, p.Value, p.depth)
90		return errorStr
91	}
