93	// MaybeResolveColor wraps resolveColor and silences possible errors, returning
94	// Transparent color by default, as a Block does not know how to handle color errors.
95	func (p Palette) MaybeResolveColor(colorName Ansi) Ansi {
96		color, err := p.ResolveColor(colorName)
97		if err != nil {
98			return ""
99		}
100	
101		return color
